fn solve(m: i64, n: i64, waitCost: Vec<Vec<i64>>) -> i64 {
    use std::cmp::Ordering;
    use std::collections::VecDeque;

    let m = m as usize;
    let n = n as usize;
    let mut dist = vec![vec![i64::MAX; n]; m];
    dist[0][0] = 1; // Initial cost to enter (0, 0)
    let mut queue = VecDeque::new();
    queue.push_back((0, 0, 0)); // (row, col, time)

    while let Some((i, j, t)) = queue.pop_front() {
        if i == m - 1 && j == n - 1 {
            break;
        }

        // If current time is odd, we can move right or down
        if t % 2 == 1 {
            // Move right
            if j + 1 < n {
                let new_i = i;
                let new_j = j + 1;
                let new_t = t + 1;
                let cost = (new_i + 1) * (new_j + 1);
                let new_dist = dist[i][j] + cost;
                if new_dist < dist[new_i][new_j] {
                    dist[new_i][new_j] = new_dist;
                    queue.push_back((new_i, new_j, new_t));
                }
            }

            // Move down
            if i + 1 < m {
                let new_i = i + 1;
                let new_j = j;
                let new_t = t + 1;
                let cost = (new_i + 1) * (new_j + 1);
                let new_dist = dist[i][j] + cost;
                if new_dist < dist[new_i][new_j] {
                    dist[new_i][new_j] = new_dist;
                    queue.push_back((new_i, new_j, new_t));
                }
            }
        } else {
            // If current time is even, we have to wait
            let new_t = t + 1;
            let cost = waitCost[i][j];
            let new_dist = dist[i][j] + cost;
            if new_dist < dist[i][j] {
                dist[i][j] = new_dist;
                queue.push_back((i, j, new_t));
            }
        }
    }

    dist[m - 1][n - 1]
}
